from utils.math_helpers import es_par, es_primo

def clasificar_numero(n):
    if es_par(n):
        if es_primo(n):
            return "par primo"
        else:
            return "par no primo"
    else:
        if es_primo(n):
            return "impar primo"
        else:
            return "impar no primo"

if __name__ == '__main__':
    try:
        assert clasificar_numero(2) == "par primo"
        assert clasificar_numero(4) == "par no primo"
        assert clasificar_numero(3) == "impar primo"
        assert clasificar_numero(9) == "impar no primo"
        print('CRITERIO OK')
    except Exception as e:
        print(f'CRITERIO FALLO: {e}')
